DECLARE
  v_opening_balance NUMERIC := 0;
  v_cash_sales NUMERIC := 0;
  v_other_income NUMERIC := 0;
  v_total_expenses NUMERIC := 0;
  v_closing_balance NUMERIC := 0;
  v_record_exists BOOLEAN := FALSE;
BEGIN
  -- Check if opening balance record exists for the target date
  SELECT EXISTS(SELECT 1 FROM daily_cash_balance WHERE balance_date = target_date)
  INTO v_record_exists;
  
  -- Get opening balance if record exists
  IF v_record_exists THEN
    SELECT COALESCE(dcb.opening_balance, 0)
    INTO v_opening_balance
    FROM daily_cash_balance dcb
    WHERE dcb.balance_date = target_date;
  ELSE
    -- No record exists, calculate from previous day's closing
    DECLARE
      v_prev_opening NUMERIC := 0;
      v_prev_sales NUMERIC := 0;
      v_prev_income NUMERIC := 0;
      v_prev_expenses NUMERIC := 0;
      v_prev_date DATE := target_date - INTERVAL '1 day';
      v_prev_record_exists BOOLEAN := FALSE;
    BEGIN
      -- Check if previous day has a record
      SELECT EXISTS(SELECT 1 FROM daily_cash_balance WHERE balance_date = v_prev_date)
      INTO v_prev_record_exists;
      
      IF v_prev_record_exists THEN
        SELECT COALESCE(dcb.opening_balance, 0)
        INTO v_prev_opening
        FROM daily_cash_balance dcb
        WHERE dcb.balance_date = v_prev_date;
      ELSE
        v_prev_opening := 0;
      END IF;
      
      -- Calculate previous day's cash sales (FIX: Added deleted_at IS NULL AND force_delete_at IS NULL)
      SELECT COALESCE(SUM(final_amount), 0)
      INTO v_prev_sales
      FROM orders
      WHERE payment_method = 'cash'
        AND DATE(created_at) = v_prev_date
        AND status = 'completed'
        AND deleted_at IS NULL
        AND force_delete_at IS NULL;
      
      -- Calculate previous day's other income
      SELECT COALESCE(SUM(amount), 0)
      INTO v_prev_income
      FROM cash_transactions
      WHERE transaction_type = 'income'
        AND transaction_date = v_prev_date;
      
      -- Calculate previous day's expenses
      SELECT COALESCE(SUM(amount), 0)
      INTO v_prev_expenses
      FROM cash_transactions
      WHERE transaction_type = 'expense'
        AND transaction_date = v_prev_date;
      
      -- Calculate previous day's closing which becomes today's opening
      v_opening_balance := v_prev_opening + v_prev_sales + v_prev_income - v_prev_expenses;
    END;
  END IF;
  
  -- Calculate cash sales from orders (only cash payment method) (FIX: Added deleted_at IS NULL AND force_delete_at IS NULL)
  SELECT COALESCE(SUM(final_amount), 0)
  INTO v_cash_sales
  FROM orders
  WHERE payment_method = 'cash'
    AND DATE(created_at) = target_date
    AND status = 'completed'
    AND deleted_at IS NULL
    AND force_delete_at IS NULL;
  
  -- Calculate other income from cash_transactions (income type)
  SELECT COALESCE(SUM(amount), 0)
  INTO v_other_income
  FROM cash_transactions
  WHERE transaction_type = 'income'
    AND transaction_date = target_date;
  
  -- Calculate total expenses from cash_transactions (expense type)
  SELECT COALESCE(SUM(amount), 0)
  INTO v_total_expenses
  FROM cash_transactions
  WHERE transaction_type = 'expense'
    AND transaction_date = target_date;
  
  -- Calculate closing balance
  v_closing_balance := v_opening_balance + v_cash_sales + v_other_income - v_total_expenses;
  
  -- Return the results
  RETURN QUERY SELECT 
    v_opening_balance,
    v_cash_sales,
    v_other_income,
    v_total_expenses,
    v_closing_balance;
END;

DECLARE
  changes_obj JSONB := '{}'::jsonb;
BEGIN
  -- Track what changed
  IF OLD.subtotal != NEW.subtotal THEN
    changes_obj := changes_obj || jsonb_build_object('subtotal', jsonb_build_object('old', OLD.subtotal, 'new', NEW.subtotal));
  END IF;
  
  IF OLD.final_amount != NEW.final_amount THEN
    changes_obj := changes_obj || jsonb_build_object('final_amount', jsonb_build_object('old', OLD.final_amount, 'new', NEW.final_amount));
  END IF;
  
  IF OLD.payment_method != NEW.payment_method THEN
    changes_obj := changes_obj || jsonb_build_object('payment_method', jsonb_build_object('old', OLD.payment_method, 'new', NEW.payment_method));
  END IF;
  
  IF OLD.status != NEW.status THEN
    changes_obj := changes_obj || jsonb_build_object('status', jsonb_build_object('old', OLD.status, 'new', NEW.status));
  END IF;
  
  -- Track notes changes (handle NULL values)
  IF (OLD.notes IS DISTINCT FROM NEW.notes) THEN
    changes_obj := changes_obj || jsonb_build_object('notes', jsonb_build_object('old', OLD.notes, 'new', NEW.notes));
  END IF;

  -- Track deleted_at changes (handle NULL values)
  IF (OLD.deleted_at IS DISTINCT FROM NEW.deleted_at) THEN
    changes_obj := changes_obj || jsonb_build_object('deleted_at', jsonb_build_object('old', OLD.deleted_at, 'new', NEW.deleted_at));
  END IF;

  -- Track force_delete_at changes (handle NULL values)
  IF (OLD.force_delete_at IS DISTINCT FROM NEW.force_delete_at) THEN
    changes_obj := changes_obj || jsonb_build_object('force_delete_at', jsonb_build_object('old', OLD.force_delete_at, 'new', NEW.force_delete_at));
  END IF;

  -- Only log if there were actual changes
  IF changes_obj != '{}'::jsonb THEN
    INSERT INTO order_audit_logs (order_id, action, changed_by, changes)
    VALUES (
      NEW.id,
      'updated',
      NEW.updated_by,
      changes_obj
    );
  END IF;
  
  RETURN NEW;
END;

BEGIN
  INSERT INTO order_audit_logs (order_id, action, changed_by, changes)
  VALUES (
    NEW.id,
    'created',
    NEW.created_by,
    jsonb_build_object(
      'subtotal', NEW.subtotal,
      'final_amount', NEW.final_amount,
      'payment_method', NEW.payment_method,
      'status', NEW.status,
      'notes', NEW.notes
    )
  );
  RETURN NEW;
END;

DECLARE
  v_opening_balance NUMERIC;
  v_prev_date DATE;
  v_prev_record_exists BOOLEAN;
BEGIN
  -- Get previous day's date
  v_prev_date := p_date - INTERVAL '1 day';
  
  -- Check if there's already a record for this date
  SELECT EXISTS(SELECT 1 FROM daily_cash_balance WHERE balance_date = p_date)
  INTO v_prev_record_exists;
  
  IF v_prev_record_exists THEN
    -- Record already exists, don't update it (allow manual overrides)
    RETURN;
  END IF;
  
  -- Calculate opening balance from previous day's closing
  SELECT
    COALESCE(
      dcb.opening_balance +
      (SELECT COALESCE(SUM(final_amount), 0) FROM orders WHERE payment_method = 'cash' AND DATE(created_at) = v_prev_date AND status = 'completed') +
      (SELECT COALESCE(SUM(amount), 0) FROM cash_transactions WHERE transaction_type = 'income' AND transaction_date = v_prev_date) -
      (SELECT COALESCE(SUM(amount), 0) FROM cash_transactions WHERE transaction_type = 'expense' AND transaction_date = v_prev_date),
      0
    )
  INTO v_opening_balance
  FROM daily_cash_balance dcb
  WHERE dcb.balance_date = v_prev_date;
  
  -- If no previous record found, default to 0
  v_opening_balance := COALESCE(v_opening_balance, 0);
  
  -- Insert or update the record
  INSERT INTO daily_cash_balance (balance_date, opening_balance, notes)
  VALUES (p_date, v_opening_balance, 'Auto-generated from transactions')
  ON CONFLICT (balance_date) DO NOTHING; -- Don't override if already exists
END;

BEGIN
  -- Only process cash orders that are not deleted or force deleted
  IF NEW.payment_method = 'cash' AND NEW.status = 'completed' AND NEW.deleted_at IS NULL AND NEW.force_delete_at IS NULL THEN
    -- Update daily_cash_balance for the order date (don't force)
    PERFORM update_daily_cash_balance_for_date(DATE(NEW.created_at), FALSE);
    
    -- Also update the next day with force to ensure chain is correct
    PERFORM update_daily_cash_balance_for_date(
      (DATE(NEW.created_at) + INTERVAL '1 day')::DATE,
      TRUE
    );
  END IF;
  
  RETURN NEW;
END;

BEGIN
  -- Update daily_cash_balance for the transaction date (don't force)
  PERFORM update_daily_cash_balance_for_date(NEW.transaction_date, FALSE);
  
  -- Also update the next day with force to ensure chain is correct
  PERFORM update_daily_cash_balance_for_date(
    (NEW.transaction_date + INTERVAL '1 day')::DATE,
    TRUE
  );
  
  RETURN NEW;
END;
